// Images des passes Wallet — embarquées en base64 (le bundler edge ne suit
// pas les fichiers statiques). Sources : icône app iOS (icon 29/58/87) +
// wordmark BLANC « yuno » (Space Grotesk 700, logo 160x50 / 320x100 / 480x150)
// + fond dégradé noir->rouge Yuno (background 180x220 .. 540x660, rendu flouté
// par Wallet sur les styles eventTicket). Régénérer via scratchpad/gen assets.

function b64(data: string): Uint8Array {
  const bin = atob(data);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}

